const b = $input.first().json.body || $input.first().json;
const required = ['projectName','profile','posts','apifyKey','geminiKey'];
for (const f of required) { if (!b[f]) throw new Error('Campo obrigatorio: ' + f); }
b.posts = Math.min(parseInt(b.posts) || 12, 100);
b.handle = (b.profile || '').replace(/^@/, '').trim();
b.profile = b.handle;
if (!b.handle) throw new Error('profile invalido');
return [{ json: b }];

const response = $input.first();
const statusCode = response.json.statusCode;
if (statusCode === 402) throw new Error('APIFY_CREDIT_EXHAUSTED');

const posts = Array.isArray(response.json.body) ? response.json.body : response.json;
if (!Array.isArray(posts) || posts.length === 0) throw new Error('Nenhum post coletado. Verifique o perfil.');

const vars = $('Validar Input').first().json;
const followerCount = posts[0]?.ownerFollowersCount || posts[0]?.followersCount || 0;

function fmt(type) {
  if (type === 'Video') return 'Reels';
  if (type === 'Image') return 'Foto';
  if (type === 'Sidecar') return 'Carrossel';
  return type || 'Foto';
}
function fmtDate(ts) {
  if (!ts) return '';
  return new Date(ts).toLocaleDateString('pt-BR');
}
function fmtLegenda(cap) {
  if (!cap) return '';
  return cap.replace(/[\r\n]+/g, ' ').trim().substring(0, 200) + (cap.length > 200 ? '...' : '');
}

const rows = posts.map(p => ({
  perfil: p.ownerUsername || vars.profile,
  link: p.url || '',
  formato: fmt(p.type),
  data: fmtDate(p.timestamp),
  curtidas: (p.likesCount !== null && p.likesCount !== undefined) ? String(p.likesCount) : 'Oculto',
  comentarios: String(p.commentsCount || 0),
  legenda: fmtLegenda(p.caption)
}));

return [{ json: { rows, geminiKey: vars.geminiKey, profile: vars.profile, projectName: vars.projectName, postsCount: rows.length, followerCount } }];

const { rows, geminiKey, profile, projectName, postsCount, followerCount } = $input.first().json;

const legends = rows.map((r, i) => `[${i+1}] Perfil: ${r.perfil} | Formato: ${r.formato} | Legenda: "${r.legenda || '(sem legenda)'}"`);

const prompt = `Você é especialista em análise de conteúdo de marcas e negócios no Instagram.

Analise os ${rows.length} posts abaixo e classifique cada um com:
- tema: categoria principal do conteúdo (seja específico e descritivo, ex: "Apresentação de produto / Lançamento", "Bastidores / Cultura da empresa", "Depoimento de cliente / Prova social", "Dica educativa / Conteúdo de valor", "Promoção / Oferta especial", "Evento / Celebração", etc.)
- tom: como o conteúdo se comunica (ex: "Inspiracional e motivacional", "Informativo e educativo", "Emocional e afetivo", "Comercial e persuasivo", "Descontraído e bem-humorado", etc.)

Retorne SOMENTE um array JSON válido com ${rows.length} objetos {"tema":"...","tom":"..."}, na mesma ordem dos posts. Sem texto adicional.

Posts:
${legends.join('\n')}`;

return [{ json: { prompt, rows, geminiKey, profile, projectName, postsCount, followerCount } }];

const geminiResponse = $input.first().json;
const { rows, profile, projectName, postsCount, followerCount } = $('Preparar Prompt Gemini').first().json;

let classifications = [];
try {
  const text = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '[]';
  classifications = JSON.parse(text);
} catch(e) {
  classifications = rows.map(() => ({ tema: 'Conteúdo geral', tom: 'Informativo' }));
}

const finalRows = rows.map((r, i) => ({
  Perfil: r.perfil,
  Link: r.link,
  Formato: r.formato,
  Data: r.data,
  Curtidas: r.curtidas,
  Comentarios: r.comentarios,
  Legenda: r.legenda,
  Tema: classifications[i]?.tema || 'Sem classificação',
  Tom_de_Voz: classifications[i]?.tom || '—',
  _projectName: projectName,
  _followerCount: followerCount
}));

return finalRows.map(row => ({ json: row }));

const items = $input.all();
const rows = items.map(item => ({
  Perfil: item.json.Perfil,
  Link: item.json.Link,
  Formato: item.json.Formato,
  Data: item.json.Data,
  Curtidas: item.json.Curtidas,
  Comentarios: item.json.Comentarios,
  Legenda: item.json.Legenda,
  Tema: item.json.Tema,
  Tom_de_Voz: item.json.Tom_de_Voz
}));

const vars = $('Validar Input').first().json;
const mapPosts = $('Mapear Posts').first().json;
const handle = vars.handle;
const projectName = vars.projectName;
const followerCount = mapPosts.followerCount || 0;
const postsCount = rows.length;

const today = new Date();
const datePart = today.toLocaleDateString('pt-BR').replace(/\//g, '-');
const sheetTitle = '@' + handle + ' · ' + projectName + ' · ' + datePart;

return [{ json: { rows, handle, projectName, postsCount, followerCount, sheetTitle } }];

const sheet = $input.first().json;
const agg = $('Agregar Linhas').first().json;

const spreadsheetId = sheet.spreadsheetId;
const spreadsheetUrl = sheet.spreadsheetUrl || ('https://docs.google.com/spreadsheets/d/' + spreadsheetId + '/edit');

const headers = ['Perfil', 'Link', 'Formato', 'Data', 'Curtidas', 'Comentários', 'Legenda', 'Tema', 'Tom de Voz'];
const valueRows = agg.rows.map(r => [
  r.Perfil || '',
  r.Link || '',
  r.Formato || '',
  r.Data || '',
  r.Curtidas || '',
  r.Comentarios || '',
  r.Legenda || '',
  r.Tema || '',
  r.Tom_de_Voz || ''
]);
const values = [headers, ...valueRows];

return [{ json: {
  spreadsheetId,
  spreadsheetUrl,
  valuesBody: { values },
  handle: agg.handle,
  projectName: agg.projectName,
  postsCount: agg.postsCount,
  followerCount: agg.followerCount,
  rows: agg.rows
} }];

const prev = $('Preparar Dados Sheet').first().json;
return [{ json: {
  status: 'success',
  handle: prev.handle,
  sheetId: prev.spreadsheetId,
  sheetUrl: prev.spreadsheetUrl,
  postsCount: prev.postsCount,
  followerCount: prev.followerCount,
  rows: prev.rows
} }];
